/**
 * symbols.js
 * Original Evangelist medallion masks generated from the supplied reference.
 * The masks are embedded as data URIs so they also work under file://.
 */

/* global SYMBOLS, SYMBOL_DATA_URIS, SYMBOL_FAVICON_PATHS */

const SYMBOL_FAVICON_PATHS = {
  mateus: 'assets/images/favicon-mateus.png',
  marcos: 'assets/images/favicon-marcos.png',
  lucas: 'assets/images/favicon-lucas.png',
  joao: 'assets/images/favicon-joao.png',
};

const SYMBOL_DATA_URIS = {
  mateus: 'data:image/png;base64,',
  marcos: 'data:image/png;base64,',
  lucas: 'data:image/png;base64,',
  joao: 'data:image/png;base64,',
};

function catenaSymbol(key) {
  return `<span class="evangelist-symbol evangelist-symbol-${key}"
    style="--symbol-src:url('${SYMBOL_DATA_URIS[key]}')"
    aria-hidden="true"></span>`;
}

const SYMBOLS = {
  mateus: catenaSymbol('mateus'),
  marcos: catenaSymbol('marcos'),
  lucas: catenaSymbol('lucas'),
  joao: catenaSymbol('joao'),
};
